724 // Replace G with a simple tail call to bitcast(F). Also (unless
725 // MergeFunctionsPDI holds) replace direct uses of G with bitcast(F),
726 // delete G. Under MergeFunctionsPDI, we use G itself for creating
727 // the thunk as we preserve the debug info (and associated instructions)
728 // from G's entry block pertaining to G's incoming arguments which are
729 // passed on as corresponding arguments in the call that G makes to F.
730 // For better debugability, under MergeFunctionsPDI, we do not modify G's
731 // call sites to point to F even when within the same translation unit.
732 void MergeFunctions::writeThunk(Function *F, Function *G) {
733   BasicBlock *GEntryBlock = nullptr;
734   std::vector<Instruction *> PDIUnrelatedWL;
735   std::vector<DbgVariableRecord *> PDVRUnrelatedWL;
736   BasicBlock *BB = nullptr;
737   Function *NewG = nullptr;
738   if (MergeFunctionsPDI) {
739     LLVM_DEBUG(dbgs() << "writeThunk: (MergeFunctionsPDI) Do not create a new "
740                          "function as thunk; retain original: "
741                       << G->getName() << "()\n");
742     GEntryBlock = &G->getEntryBlock();
743     LLVM_DEBUG(
744         dbgs() << "writeThunk: (MergeFunctionsPDI) filter parameter related "
745                   "debug info for "
746                << G->getName() << "() {\n");
747     filterInstsUnrelatedToPDI(GEntryBlock, PDIUnrelatedWL, PDVRUnrelatedWL);
748     GEntryBlock->getTerminator()->eraseFromParent();
749     BB = GEntryBlock;
750   } else {
751     NewG = Function::Create(G->getFunctionType(), G->getLinkage(),
752                             G->getAddressSpace(), "", G->getParent());
753     NewG->setComdat(G->getComdat());
754     BB = BasicBlock::Create(F->getContext(), "", NewG);
755   }
756 
757   IRBuilder<> Builder(BB);
758   Function *H = MergeFunctionsPDI ? G : NewG;
759   SmallVector<Value *, 16> Args;
760   unsigned i = 0;
761   FunctionType *FFTy = F->getFunctionType();
762   for (Argument &AI : H->args()) {
763     Args.push_back(Builder.CreateAggregateCast(&AI, FFTy->getParamType(i)));
764     ++i;
765   }
766 
767   CallInst *CI = Builder.CreateCall(F, Args);
768   ReturnInst *RI = nullptr;
769   bool isSwiftTailCall = F->getCallingConv() == CallingConv::SwiftTail &&
770                          G->getCallingConv() == CallingConv::SwiftTail;
771   CI->setTailCallKind(isSwiftTailCall ? CallInst::TCK_MustTail
772                                       : CallInst::TCK_Tail);
773   CI->setCallingConv(F->getCallingConv());
774   CI->setAttributes(F->getAttributes());
775   if (H->getReturnType()->isVoidTy()) {
776     RI = Builder.CreateRetVoid();
777   } else {
778     RI = Builder.CreateRet(Builder.CreateAggregateCast(CI, H->getReturnType()));
779   }
780 
781   if (MergeFunctionsPDI) {
782     DISubprogram *DIS = G->getSubprogram();
783     if (DIS) {
784       DebugLoc CIDbgLoc =
785           DILocation::get(DIS->getContext(), DIS->getScopeLine(), 0, DIS);
786       DebugLoc RIDbgLoc =
787           DILocation::get(DIS->getContext(), DIS->getScopeLine(), 0, DIS);
788       CI->setDebugLoc(CIDbgLoc);
789       RI->setDebugLoc(RIDbgLoc);
790     } else {
791       LLVM_DEBUG(
792           dbgs() << "writeThunk: (MergeFunctionsPDI) No DISubprogram for "
793                  << G->getName() << "()\n");
794     }
795     eraseTail(G);
796     eraseInstsUnrelatedToPDI(PDIUnrelatedWL, PDVRUnrelatedWL);
797     LLVM_DEBUG(
798         dbgs() << "} // End of parameter related debug info filtering for: "
799                << G->getName() << "()\n");
800   } else {
801     NewG->copyAttributesFrom(G);
802     NewG->takeName(G);
803     // Ensure CFI type metadata is propagated to the new function.
804     copyMetadataIfPresent(G, NewG, "type");
805     copyMetadataIfPresent(G, NewG, "kcfi_type");
806     removeUsers(G);
807     G->replaceAllUsesWith(NewG);
808     G->eraseFromParent();
809   }
