850 // If needed, replace G with an alias to F if possible, or a thunk to F if
851 // profitable. Returns false if neither is the case. If \p G is not needed (i.e.
852 // it is discardable and unused), \p G is removed directly.
853 bool MergeFunctions::writeThunkOrAliasIfNeeded(Function *F, Function *G) {
854   if (G->isDiscardableIfUnused() && G->use_empty() && !MergeFunctionsPDI) {
855     G->eraseFromParent();
856     return true;
857   }
858   if (canCreateAliasFor(G)) {
859     writeAlias(F, G);
860     return true;
861   }
862   if (canCreateThunkFor(F)) {
863     writeThunk(F, G);
864     return true;
865   }
866   return false;
867 }
