874 // Merge two equivalent functions. Upon completion, Function G is deleted.
875 void MergeFunctions::mergeTwoFunctions(Function *F, Function *G) {
876 
877   // Create a new thunk that both F and G can call, if F cannot call G directly.
878   // That is the case if F is either interposable or if G is either weak_odr or
879   // linkonce_odr.
880   if (F->isInterposable() || (isODR(F) && isODR(G))) {
881     assert((!isODR(G) || isODR(F)) &&
882            "if G is ODR, F must also be ODR due to ordering");
883 
884     // Both writeThunkOrAliasIfNeeded() calls below must succeed, either because
885     // we can create aliases for G and NewF, or because a thunk for F is
886     // profitable. F here has the same signature as NewF below, so that's what
887     // we check.
888     if (!canCreateThunkFor(F) &&
889         (!canCreateAliasFor(F) || !canCreateAliasFor(G)))
890       return;
891 
892     // Make them both thunks to the same internal function.
893     Function *NewF = Function::Create(F->getFunctionType(), F->getLinkage(),
894                                       F->getAddressSpace(), "", F->getParent());
895     NewF->copyAttributesFrom(F);
896     NewF->takeName(F);
897     NewF->setComdat(F->getComdat());
898     F->setComdat(nullptr);
899     // Ensure CFI type metadata is propagated to the new function.
