1009 // Insert a ComparableFunction into the FnTree, or merge it away if equal to one
1010 // that was already inserted.
1011 bool MergeFunctions::insert(Function *NewFunction) {
1012   std::pair<FnTreeType::iterator, bool> Result =
1013       FnTree.insert(FunctionNode(NewFunction));
1014 
1015   if (Result.second) {
1016     assert(FNodesInTree.count(NewFunction) == 0);
1017     FNodesInTree.insert({NewFunction, Result.first});
1018     LLVM_DEBUG(dbgs() << "Inserting as unique: " << NewFunction->getName()
1019                       << '\n');
1020     return false;
1021   }
1022 
1023   const FunctionNode &OldF = *Result.first;
1024 
1025   if (!isFuncOrderCorrect(OldF.getFunc(), NewFunction)) {
1026     // Swap the two functions.
1027     Function *F = OldF.getFunc();
1028     replaceFunctionInTree(*Result.first, NewFunction);
1029     NewFunction = F;
1030     assert(OldF.getFunc() != F && "Must have swapped the functions.");
1031   }
1032 
1033   // Capture the Function pointer before mergeTwoFunctions, which may invalidate
1034   // OldF by erasing it from FnTree via removeUsers().
1035   Function *OldFunc = OldF.getFunc();
1036 
1037   LLVM_DEBUG(dbgs() << "  " << OldFunc->getName()
1038                     << " == " << NewFunction->getName() << '\n');
1039 
1040   Function *DeleteF = NewFunction;
1041   mergeTwoFunctions(OldFunc, DeleteF);
1042   this->DelToNewMap.insert({DeleteF, OldFunc});
1043   return true;
1044 }
