 858   if (canCreateAliasFor(G)) {
 859     writeAlias(F, G);
 860     return true;
 861   }
 862   if (canCreateThunkFor(F)) {
 863     writeThunk(F, G);
 864     return true;
 865   }
 866   return false;
 867 }
