 983 // Ordering for functions that are equal under FunctionComparator
 984 static bool isFuncOrderCorrect(const Function *F, const Function *G) {
 985   if (isODR(F) != isODR(G)) {
 986     // ODR functions before non-ODR functions. A ODR function can call a non-ODR
 987     // function if it is not interposable, but not the other way around.
 988     return isODR(G);
 989   }
 990 
 991   if (F->isInterposable() != G->isInterposable()) {
 992     // Strong before weak, because the weak function may call the strong
 993     // one, but not the other way around.
 994     return !F->isInterposable();
 995   }
 996 
 997   if (F->hasLocalLinkage() != G->hasLocalLinkage()) {
 998     // External before local, because we definitely have to keep the external
 999     // function, but may be able to drop the local one.
1000     return !F->hasLocalLinkage();
1001   }
1002 
1003   // Impose a total order (by name) on the replacement of functions. This is
1004   // important when operating on more than one module independently to prevent
1005   // cycles of thunks calling each other when the modules are linked together.
1006   return F->getName() <= G->getName();
1007 }
