1046 // Remove a function from FnTree. If it was already in FnTree, add
1047 // it to Deferred so that we'll look at it in the next round.
1048 void MergeFunctions::remove(Function *F) {
1049   auto I = FNodesInTree.find(F);
1050   if (I != FNodesInTree.end()) {
1051     LLVM_DEBUG(dbgs() << "Deferred " << F->getName() << ".\n");
1052     FnTree.erase(I->second);
1053     // I->second has been invalidated, remove it from the FNodesInTree map to
1054     // preserve the invariant.
1055     FNodesInTree.erase(I);
1056     Deferred.emplace_back(F);
1057   }
1058 }
